import Link from "next/link";
import { Tag, MapPin, Calendar, ChevronRight, Trash2, Eye } from "lucide-react";

const WideCard = ({ item, onDelete }) => {
  const getStatusColor = (status) => {
    switch (status?.toLowerCase()) {
      case "pending":
        return "text-amber-500 bg-amber-50 border-amber-100";
      case "accepted":
        return "text-emerald-500 bg-emerald-50 border-emerald-100";
      default:
        return "text-indigo-500 bg-indigo-50 border-indigo-100";
    }
  };

  return (
    <div className="group relative w-full mb-6 max-w-5xl mx-auto">
      {/* Main Card - Increased min-height */}
      <div className="flex bg-white border border-gray-100 rounded-[2.5rem] p-6 shadow-sm hover:shadow-2xl hover:border-indigo-100 transition-all duration-500 min-h-[220px]">
        {/* 1. Image Section - Larger Height */}
        <div className="relative h-44 w-44 md:h-52 md:w-52 flex-shrink-0 overflow-hidden rounded-[2rem] shadow-md">
          <img
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
            src={item.photos?.[0] || "https://placehold.co/400?text=No+Photo"}
            alt={item.itemName}
          />
          <div className="absolute top-3 left-3">
            <span
              className={`px-3 py-1.5 text-[10px] font-black uppercase rounded-xl border backdrop-blur-md bg-white/80 shadow-sm ${getStatusColor(item.status)}`}
            >
              {item.status}
            </span>
          </div>
        </div>

        {/* 2. Content Section - Using Flex Column for Bottom Alignment */}
        <div className="flex flex-col flex-grow px-8 justify-between">
          {/* Top Content */}
          <div>
            <div className="flex justify-between items-start mb-3">
              <h3 className="text-3xl font-black text-gray-800 tracking-tight">
                {item.itemName}
              </h3>
            </div>

            <div className="flex flex-wrap gap-x-6 gap-y-2 mb-4">
              <div className="flex items-center text-sm text-gray-400 font-bold uppercase tracking-wider">
                <Tag className="w-4 h-4 mr-2 text-indigo-500" />
                {item.category || "General"}
              </div>
              <div className="flex items-center text-sm text-gray-500 font-medium">
                <MapPin className="w-4 h-4 mr-2 text-rose-500" />
                {item.location}
              </div>
              <div className="flex items-center text-sm text-gray-500 font-medium">
                <Calendar className="w-4 h-4 mr-2 text-amber-500" />
                {new Date(item.date).toLocaleDateString("en-GB")}
              </div>
            </div>

            {/* Description added to fill space */}
            <p className="text-gray-500 text-sm line-clamp-2 leading-relaxed max-w-xl">
              {item.description ||
                "No additional description provided for this item."}
            </p>
          </div>

          {/* 3. Bottom Actions Section */}
          <div className="flex items-center gap-3 pt-6">
            <Link href={`/item/${item._id}`} className="flex-1 max-w-[160px]">
              <button className="w-full flex items-center justify-center gap-2 py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-2xl text-xs font-bold transition-all active:scale-95">
                <Eye className="w-4 h-4" />
                View Details
              </button>
            </Link>

            <Link
              href={`/claimItem/${item._id}`}
              className="flex-1 max-w-[160px]"
            >
              <button className="w-full py-3 bg-indigo-600 hover:bg-black text-white rounded-2xl text-xs font-bold transition-all shadow-lg shadow-indigo-100 active:scale-95">
                Claim Now
              </button>
            </Link>

            {/* Optional Delete Button (Moved to bottom right) */}
            <button
              onClick={() => onDelete?.(item._id)}
              className="ml-auto p-3 text-gray-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Mobile-only Arrow */}
        <div className="md:hidden flex items-center">
          <ChevronRight className="w-6 h-6 text-gray-300" />
        </div>
      </div>
    </div>
  );
};

export default WideCard;
